firmware_template.source:
#include "ads1115_sensor.h"
#include <Wire.h>
#include <Adafruit_ADS1X15.h>
#include "config.h"

static Adafruit_ADS1115 _ads;
static bool _adsReady = false;
static float _voltages[4] = {0};
static int16_t _rawValues[4] = {0};

void ads1115_setup() {
    Wire.begin(21, 22);
    if (_ads.begin(0x48, &Wire)) {
        _adsReady = true;
        _ads.setGain(GAIN_ONE); // +/- 4.096V range
        _ads.setDataRate(RATE_ADS1115_128SPS);
        Serial.println("[ads1115] 16-bit ADC ready");
    } else {
        Serial.println("[ads1115] FAILED");
    }
}

void ads1115_loop() {
    if (!_adsReady) return;
    for (int ch = 0; ch < 4; ch++) {
        _rawValues[ch] = _ads.readADC_SingleEnded(ch);
        _voltages[ch] = _ads.computeVolts(_rawValues[ch]);
    }
}

float ads1115_voltage(int channel) {
    return (channel >= 0 && channel < 4) ? _voltages[channel] : 0;
}

int16_t ads1115_raw(int channel) {
    return (channel >= 0 && channel < 4) ? _rawValues[channel] : 0;
}

bool ads1115_ready() { return _adsReady; }
